#pragma once

#include <cuda_runtime.h>
#include <cuda_fp16.h>
#include <cuda_bf16.h>
#include <stdint.h>
#include <cstdio>
#include <cstdlib>

// RMSNorm kernel parameters
constexpr float RMSNORM_EPS = 1e-5f;
constexpr int HIDDEN_SIZE = 4096;

// Kernel launch configuration for A800
constexpr int BLOCK_SIZE = 256;

// CUDA error checking macro
#define CUDA_CHECK(call) \
    do { \
        cudaError_t err = call; \
        if (err != cudaSuccess) { \
            fprintf(stderr, "CUDA error at %s:%d: %s\n", __FILE__, __LINE__, \
                    cudaGetErrorString(err)); \
            exit(EXIT_FAILURE); \
        } \
    } while(0)

/**
 * RMSNorm CUDA kernel
 * @param hidden_states Input tensor [batch_size, hidden_size] in BFLOAT16
 * @param weight Weight vector [hidden_size] in BFLOAT16
 * @param output Output tensor [batch_size, hidden_size] in BFLOAT16
 * @param batch_size Number of rows
 */
__global__ void rmsnorm_kernel(
    const __nv_bfloat16* hidden_states,
    const __nv_bfloat16* weight,
    __nv_bfloat16* output,
    int batch_size
);

/**
 * Host function to launch RMSNorm kernel
 * @param hidden_states Input tensor pointer
 * @param weight Weight pointer
 * @param output Output tensor pointer
 * @param batch_size Number of rows
 */
void launch_rmsnorm_kernel(
    const __nv_bfloat16* hidden_states,
    const __nv_bfloat16* weight,
    __nv_bfloat16* output,
    int batch_size
);

#include "kernel.h"

/**
 * RMSNorm kernel optimized for A800
 * - Each block processes one row
 * - Block-level reduction using shared memory
 * - Coalesced memory access patterns
 * - BFLOAT16 input/output with FP32 intermediate computation
 * - Warp-level primitives for better performance on A800
 */
__global__ void rmsnorm_kernel(
    const __nv_bfloat16* hidden_states,
    const __nv_bfloat16* weight,
    __nv_bfloat16* output,
    int batch_size
) {
    int row_idx = blockIdx.x;
    int col_offset = threadIdx.x;

    if (row_idx >= batch_size) return;

    // Shared memory for block-level reduction
    extern __shared__ float shared_sum[];

    // Compute partial sum of squares for this thread's elements
    float sum_sq = 0.0f;
    for (int i = col_offset; i < HIDDEN_SIZE; i += BLOCK_SIZE) {
        float x = __bfloat162float(hidden_states[row_idx * HIDDEN_SIZE + i]);
        sum_sq += x * x;
    }

    // Block-level reduction in shared memory
    shared_sum[threadIdx.x] = sum_sq;
    __syncthreads();

    // Parallel reduction with warp-level optimization
    for (int stride = BLOCK_SIZE / 2; stride > 0; stride >>= 1) {
        if (threadIdx.x < stride) {
            shared_sum[threadIdx.x] += shared_sum[threadIdx.x + stride];
        }
        __syncthreads();
    }

    // Get the final sum from thread 0
    float row_sum_sq = shared_sum[0];

    // Compute inverse RMS using rsqrtf for better performance
    float mean_sq = row_sum_sq / HIDDEN_SIZE;
    float inv_rms = rsqrtf(mean_sq + RMSNORM_EPS);

    // Apply normalization and weight
    for (int i = col_offset; i < HIDDEN_SIZE; i += BLOCK_SIZE) {
        float x = __bfloat162float(hidden_states[row_idx * HIDDEN_SIZE + i]);
        float w = __bfloat162float(weight[i]);
        float y = x * inv_rms * w;
        output[row_idx * HIDDEN_SIZE + i] = __float2bfloat16(y);
    }
}

/**
 * Host function to launch RMSNorm kernel with optimal configuration
 */
void launch_rmsnorm_kernel(
    const __nv_bfloat16* hidden_states,
    const __nv_bfloat16* weight,
    __nv_bfloat16* output,
    int batch_size
) {
    // Calculate grid dimensions - one block per row
    int num_blocks = batch_size;

    // Shared memory size for reduction
    size_t shared_mem_size = BLOCK_SIZE * sizeof(float);

    // Launch kernel
    rmsnorm_kernel<<<num_blocks, BLOCK_SIZE, shared_mem_size>>>(
        hidden_states,
        weight,
        output,
        batch_size
    );

    // Check for launch errors
    cudaError_t err = cudaGetLastError();
    if (err != cudaSuccess) {
        fprintf(stderr, "Kernel launch error: %s\n", cudaGetErrorString(err));
    }

    // Synchronize to ensure completion
    CUDA_CHECK(cudaDeviceSynchronize());
}

#include <torch/extension.h>
#include <ATen/ATen.h>
#include <ATen/cuda/CUDAContext.h>
#include <ATen/cuda/CUDADataType.h>
#include <cuda_runtime.h>
#include <cuda_bf16.h>
#include "kernel.h"
#include <cstdio>
#include <string>

// Validate tensor properties
void validate_tensor(const torch::Tensor& tensor, const std::string& name, 
                     at::ScalarType expected_dtype, at::DeviceType expected_device) {
    TORCH_CHECK(tensor.is_contiguous(), name + " must be contiguous");
    TORCH_CHECK(tensor.dtype() == expected_dtype, 
                name + " must have dtype " + torch::str(expected_dtype));
    TORCH_CHECK(tensor.device().type() == expected_device, 
                name + " must be on CUDA device");
}

/**
 * RMSNorm forward pass
 * @param hidden_states Input tensor [batch_size, hidden_size] in BFLOAT16
 * @param weight Weight tensor [hidden_size] in BFLOAT16
 * @param output Output tensor [batch_size, hidden_size] in BFLOAT16 (passed in to be filled)
 * @return Output tensor [batch_size, hidden_size] in BFLOAT16
 */
torch::Tensor run(const torch::Tensor& hidden_states, 
                  const torch::Tensor& weight,
                  torch::Tensor& output) {
    // Validate inputs
    TORCH_CHECK(hidden_states.dim() == 2, 
                "hidden_states must be 2D tensor");
    TORCH_CHECK(weight.dim() == 1, 
                "weight must be 1D tensor");
    TORCH_CHECK(output.dim() == 2, 
                "output must be 2D tensor");

    // Check hidden size matches constant
    TORCH_CHECK(hidden_states.size(1) == HIDDEN_SIZE, 
                "hidden_size must be " + std::to_string(HIDDEN_SIZE));
    TORCH_CHECK(weight.size(0) == HIDDEN_SIZE, 
                "weight size must be " + std::to_string(HIDDEN_SIZE));
    TORCH_CHECK(output.size(1) == HIDDEN_SIZE, 
                "output hidden_size must be " + std::to_string(HIDDEN_SIZE));
    TORCH_CHECK(output.size(0) == hidden_states.size(0), 
                "output batch_size must match hidden_states batch_size");

    // Validate dtypes and devices
    validate_tensor(hidden_states, "hidden_states", 
                    at::kBFloat16, at::kCUDA);
    validate_tensor(weight, "weight", 
                    at::kBFloat16, at::kCUDA);
    validate_tensor(output, "output", 
                    at::kBFloat16, at::kCUDA);

    // Get batch size
    int batch_size = static_cast<int>(hidden_states.size(0));

    // Get raw pointers using proper data_ptr for bfloat16
    // Use reinterpret_cast to get __nv_bfloat16 pointer from torch tensor
    const __nv_bfloat16* hidden_states_ptr = 
        reinterpret_cast<const __nv_bfloat16*>(hidden_states.data_ptr<c10::BFloat16>());
    const __nv_bfloat16* weight_ptr = 
        reinterpret_cast<const __nv_bfloat16*>(weight.data_ptr<c10::BFloat16>());
    __nv_bfloat16* output_ptr = 
        reinterpret_cast<__nv_bfloat16*>(output.data_ptr<c10::BFloat16>());

    // Launch kernel
    launch_rmsnorm_kernel(hidden_states_ptr, weight_ptr, output_ptr, batch_size);

    return output;
}

// PyTorch extension binding
PYBIND11_MODULE(TORCH_EXTENSION_NAME, m) {
    m.def("run", &run, "RMSNorm kernel execution function");
}
